/*
 * Geist Mono font — loaded from CDN. In production this would come from
 * the host app's font stack or be self-hosted.
 * Must precede @import "tailwindcss" because CSS @import rules must come
 * before all other statements in the compiled output.
 */
@import url("https://fonts.googleapis.com/css2?family=Geist+Mono:wght@300..900&display=swap");

@import "tailwindcss";

/*
 * Map HostBridge DesignTokens (set as CSS custom properties by AppShell)
 * into Tailwind's theme so utilities like bg-primary, text-muted, etc. work.
 *
 * Design direction: monochrome utilitarian — Geist Mono everywhere, zero
 * radius, neutral gray primary, minimal shadow. All colors resolve through
 * CSS vars so the host app can override at runtime.
 */

@theme {
  /* ── Colors ──────────────────────────────────────────────────────── */
  --color-primary: var(--color-primary, #737373);
  --color-primary-foreground: #fafafa;
  --color-secondary: var(--color-secondary, #f5f5f5);
  --color-secondary-foreground: #171717;
  --color-surface: var(--color-surface, #ffffff);
  --color-surface-raised: #fafafa;
  --color-background: var(--color-background, #ffffff);
  --color-foreground: var(--color-text, #0a0a0a);
  --color-muted: var(--color-text-muted, #717171);
  --color-muted-bg: #f5f5f5;
  --color-border: var(--color-border, #e5e5e5);
  --color-input: #e5e5e5;
  --color-ring: #a1a1a1;
  /* ── Semantic status colors (WCAG AA-validated, muted palette) ──── */
  /* Light-mode base values pass ≥4.5:1 contrast against their respective   */
  /* bg tokens. Foreground (#fafafa) passes ≥4.5:1 on each base.            */
  --color-success: var(--color-success, #3D7A4A);
  --color-success-bg: #EEF3EF;
  --color-success-border: #C7D6CB;
  --color-success-foreground: #fafafa;
  --color-warning: var(--color-warning, #7A6520);
  --color-warning-bg: #F5F2EA;
  --color-warning-border: #DDD2B8;
  --color-warning-foreground: #fafafa;
  --color-danger: var(--color-danger, #9B3B3B);
  --color-danger-bg: #F6EEEE;
  --color-danger-border: #E2CACA;
  --color-danger-foreground: #fafafa;
  /* Info/AI — CSS-only token (not in host DesignTokens contract)            */
  --color-info: var(--color-info, #4A5578);
  --color-info-bg: #EEF1F6;
  --color-info-border: #CCD3E0;
  --color-info-foreground: #fafafa;

  /* ── Typography ──────────────────────────────────────────────────── */
  --font-family-base: var(--font-family-base, "Geist Mono", ui-monospace, SFMono-Regular, "SF Mono", Menlo, Consolas, "Liberation Mono", monospace);
  --font-family-mono: "Geist Mono", ui-monospace, SFMono-Regular, "SF Mono", Menlo, Consolas, "Liberation Mono", monospace;

  /* ── Radii (0rem = sharp corners everywhere) ─────────────────────── */
  --radius-sm: calc(var(--border-radius, 0rem) * 0.75);
  --radius-default: var(--border-radius, 0rem);
  --radius-md: calc(var(--border-radius, 0rem) * 1.25);
  --radius-lg: calc(var(--border-radius, 0rem) * 2);
  --radius-full: 9999px;

  /* ── Shadows (minimal — 1px y-offset, low opacity) ───────────────── */
  --shadow-sm: 0 1px 2px 0 rgba(0, 0, 0, 0.05);
  --shadow-md: 0 1px 3px 0 rgba(0, 0, 0, 0.08);
  --shadow-lg: 0 2px 8px 0 rgba(0, 0, 0, 0.08);
}

/*
 * ── Dark mode ─────────────────────────────────────────────────────────
 *
 * Activated by <html data-theme="dark">. Every semantic color is remapped;
 * components pick up the change automatically through CSS vars.
 * The palette is the same neutral gray family, just inverted.
 */

@layer base {
  [data-theme="dark"] {
    --color-primary: #a3a3a3;
    --color-primary-foreground: #0a0a0a;
    --color-secondary: #1c1c1c;
    --color-secondary-foreground: #e5e5e5;
    --color-surface: #141414;
    --color-surface-raised: #1c1c1c;
    --color-background: #0a0a0a;
    --color-foreground: #e5e5e5;
    --color-text: #e5e5e5;
    --color-muted: #737373;
    --color-text-muted: #737373;
    --color-muted-bg: #1c1c1c;
    --color-border: #2a2a2a;
    --color-input: #2a2a2a;
    --color-ring: #525252;
    /* ── Dark-mode semantic colors (muted, lightened for ≥4.5:1 on dark bgs) */
    --color-success: #8FBF9A;
    --color-success-bg: #1A221C;
    --color-success-border: #2F3E33;
    --color-success-foreground: #0a0a0a;
    --color-warning: #C4AC6A;
    --color-warning-bg: #211F18;
    --color-warning-border: #3A3526;
    --color-warning-foreground: #0a0a0a;
    --color-danger: #D4A0A0;
    --color-danger-bg: #221A1A;
    --color-danger-border: #3B2A2A;
    --color-danger-foreground: #0a0a0a;
    --color-info: #9DABC8;
    --color-info-bg: #1A1D24;
    --color-info-border: #2F3542;
    --color-info-foreground: #0a0a0a;

    --shadow-sm: 0 1px 2px 0 rgba(0, 0, 0, 0.3);
    --shadow-md: 0 1px 3px 0 rgba(0, 0, 0, 0.4);
    --shadow-lg: 0 2px 8px 0 rgba(0, 0, 0, 0.5);

    color-scheme: dark;
  }
}

/* ── Base resets ─────────────────────────────────────────────────────── */

@layer base {
  html {
    -webkit-font-smoothing: antialiased;
    -moz-osx-font-smoothing: grayscale;
  }

  body {
    font-family: var(--font-family-base);
    color: var(--color-foreground);
    background: var(--color-background);
    font-feature-settings: "ss01", "ss02", "cv01";
  }

  /* Accessible focus ring — uses the ring color token */
  :focus-visible {
    outline: 2px solid var(--color-ring);
    outline-offset: 2px;
  }

  /* Remove default focus for mouse users */
  :focus:not(:focus-visible) {
    outline: none;
  }

  .visually-hidden {
    position: absolute;
    width: 1px;
    height: 1px;
    padding: 0;
    margin: -1px;
    overflow: hidden;
    clip: rect(0, 0, 0, 0);
    white-space: nowrap;
    border: 0;
  }
}

/* ── Scrollbar styling ───────────────────────────────────────────────── */

@layer base {
  ::-webkit-scrollbar {
    width: 6px;
    height: 6px;
  }
  ::-webkit-scrollbar-track {
    background: transparent;
  }
  ::-webkit-scrollbar-thumb {
    background: var(--color-border);
    border-radius: var(--radius-full);
    transition: background 0.2s;
  }
  ::-webkit-scrollbar-thumb:hover {
    background: var(--color-muted);
  }
}

/* ── Theme transition ────────────────────────────────────────────────── */

@layer base {
  [data-theme] {
    transition: background-color 0.2s ease, color 0.2s ease, border-color 0.2s ease;
  }
}

/* ── Chess piece shade tokens ─────────────────────────────────────────
 * Used by Reports, ChessDistributionSection, and AnswerRenderer via
 * var(--chess-king) etc. Flip to light shades in dark mode so the
 * gradient still reads darkest=KING → lightest=PAWN relative to bg.
 */

@layer base {
  :root {
    --chess-king: #0a0a0a;
    --chess-queen: #262626;
    --chess-rook: #525252;
    --chess-bishop: #737373;
    --chess-knight: #a3a3a3;
    --chess-pawn: #d4d4d4;
  }
  [data-theme="dark"] {
    --chess-king: #f5f5f5;
    --chess-queen: #d4d4d4;
    --chess-rook: #a3a3a3;
    --chess-bishop: #737373;
    --chess-knight: #525252;
    --chess-pawn: #2a2a2a;
  }
}

/* ── Transitions ─────────────────────────────────────────────────────── */

@layer utilities {
  .transition-sidebar {
    transition: width 200ms ease-in-out, padding 200ms ease-in-out;
  }
}

import type { ReactNode } from "react";
import type {
  HostContext,
  DesignTokens,
  NotificationBridge,
  TelemetryCallback,
  NavigationBridge,
} from "@weekly-commit/shared";
import { HostProvider, type HostBridge } from "./HostProvider.js";

/**
 * Default design tokens for standalone development (maps to CSS custom props).
 *
 * Design direction: monochrome utilitarian — Geist Mono everywhere, zero
 * radius, neutral gray primary, minimal shadow. Inspired by shadcn/ui
 * "New York" neutral theme.
 */
export const defaultDesignTokens: DesignTokens = {
  colorPrimary: "#737373",
  colorSecondary: "#f5f5f5",
  colorBackground: "#ffffff",
  colorSurface: "#ffffff",
  colorText: "#0a0a0a",
  colorTextMuted: "#717171",
  colorBorder: "#e5e5e5",
  colorSuccess: "#3D7A4A",
  colorWarning: "#7A6520",
  colorDanger: "#9B3B3B",
  fontFamilyBase:
    "'Geist Mono', ui-monospace, SFMono-Regular, 'SF Mono', Menlo, Consolas, 'Liberation Mono', monospace",
  fontSizeBase: "16px",
  borderRadius: "0px",
  spacingUnit: "8px",
};

/** Mock host context used during standalone dev and unit tests. */
export const mockHostContext: HostContext = {
  authenticatedUser: {
    id: "00000000-0000-0000-0000-000000000001",
    email: "dev@example.com",
    displayName: "Dev User",
  },
  currentTeam: {
    id: "00000000-0000-0000-0000-000000000010",
    name: "Engineering",
  },
  managerChain: [
    {
      id: "00000000-0000-0000-0000-000000000002",
      email: "manager@example.com",
      displayName: "Manager One",
    },
  ],
  environment: "development",
  featureFlags: {
    aiAssistanceEnabled: true,
    managerReviewEnabled: true,
    notificationsEnabled: true,
    rcdoAdminEnabled: true,
  },
  authToken: "mock-dev-token",
};

const mockNotifications: NotificationBridge = {
  showToast({ type, message }) {
    // In dev mode, log toasts to the console
    console.info(`[toast:${type}] ${message}`);
  },
};

const mockTelemetry: TelemetryCallback = {
  trackEvent(eventName, properties) {
    console.debug("[telemetry:event]", eventName, properties);
  },
  trackError(error, context) {
    console.error("[telemetry:error]", error, context);
  },
};

const mockNavigation: NavigationBridge = {
  navigateTo(path) {
    console.info("[navigation:navigateTo]", path);
  },
  getBasePath() {
    return "/weekly";
  },
};

export const mockHostBridge: HostBridge = {
  context: mockHostContext,
  tokens: defaultDesignTokens,
  notifications: mockNotifications,
  telemetry: mockTelemetry,
  navigation: mockNavigation,
};

interface MockHostProviderProps {
  readonly bridge?: HostBridge;
  readonly children: ReactNode;
}

/**
 * Drop-in replacement for HostProvider in standalone dev mode and unit tests.
 * Passes sensible mock data for all host bridge contracts.
 */
export function MockHostProvider({
  bridge = mockHostBridge,
  children,
}: MockHostProviderProps) {
  return <HostProvider bridge={bridge}>{children}</HostProvider>;
}

/**
 * App shell — polished sidebar + header + content layout.
 * Applies design tokens as CSS custom properties on the root element.
 * Sidebar is collapsible with state persisted to localStorage.
 */
import { type ReactNode, useState, useEffect } from "react";
import type { DesignTokens } from "@weekly-commit/shared";
import { useHostBridge } from "../host/HostProvider.js";
import { Navigation } from "./Navigation.js";
import { Header, getWeekMonday } from "./Header.js";
import { cn } from "../lib/utils.js";
import { useTheme } from "../lib/useTheme.js";

interface AppShellProps {
  readonly children: ReactNode;
}

const SIDEBAR_KEY = "wc-sidebar-collapsed";

/**
 * Converts DesignTokens into CSS custom properties.
 *
 * When dark mode is active, color tokens are omitted so the CSS
 * [data-theme="dark"] overrides in index.css take effect. Non-color
 * tokens (font, spacing, radius) always apply.
 */
function tokensToStyle(
  tokens: DesignTokens,
  isDark: boolean,
): React.CSSProperties {
  const base: Record<string, string> = {
    "--font-family-base": tokens.fontFamilyBase,
    "--font-size-base": tokens.fontSizeBase,
    "--border-radius": tokens.borderRadius,
    "--spacing-unit": tokens.spacingUnit,
  };

  if (!isDark) {
    // In light mode (or host-provided), apply color tokens as inline vars
    // so the host app's palette overrides our CSS defaults.
    Object.assign(base, {
      "--color-primary": tokens.colorPrimary,
      "--color-secondary": tokens.colorSecondary,
      "--color-background": tokens.colorBackground,
      "--color-surface": tokens.colorSurface,
      "--color-text": tokens.colorText,
      "--color-text-muted": tokens.colorTextMuted,
      "--color-border": tokens.colorBorder,
      "--color-success": tokens.colorSuccess,
      "--color-warning": tokens.colorWarning,
      "--color-danger": tokens.colorDanger,
    });
  }

  return base as React.CSSProperties;
}

export function AppShell({ children }: AppShellProps) {
  const { tokens } = useHostBridge();
  const { resolved } = useTheme();
  const isDark = resolved === "dark";
  const [selectedWeek, setSelectedWeek] = useState(() =>
    getWeekMonday(new Date()),
  );
  const [collapsed, setCollapsed] = useState(() => {
    try {
      return localStorage.getItem(SIDEBAR_KEY) === "true";
    } catch {
      return false;
    }
  });

  useEffect(() => {
    try {
      localStorage.setItem(SIDEBAR_KEY, String(collapsed));
    } catch {
      // ignore
    }
  }, [collapsed]);

  return (
    <div
      className="flex h-screen flex-col overflow-hidden bg-background text-foreground"
      style={{
        ...tokensToStyle(tokens, isDark),
        fontFamily: "var(--font-family-base)",
        fontSize: "var(--font-size-base)",
      }}
      data-testid="app-shell"
    >
      {/* Header */}
      <Header
        selectedWeek={selectedWeek}
        onWeekChange={setSelectedWeek}
        collapsed={collapsed}
        onToggleSidebar={() => setCollapsed((c) => !c)}
      />

      {/* Body: sidebar + main */}
      <div className="flex flex-1 overflow-hidden">
        {/* Sidebar */}
        <aside
          className={cn(
            "flex shrink-0 flex-col border-r border-border bg-surface transition-sidebar overflow-y-auto overflow-x-hidden",
            collapsed ? "w-14 px-1.5 py-4" : "w-56 px-3 py-4",
          )}
          aria-label="Sidebar"
        >
          {/* Brand mark in sidebar — visible when expanded */}
          {!collapsed && (
            <div className="mb-6 px-3">
              <p className="text-[10px] font-semibold uppercase tracking-widest text-muted">
                Navigation
              </p>
            </div>
          )}

          <Navigation collapsed={collapsed} />

          {/* Spacer pushes bottom content down */}
          <div className="flex-1" />

          {/* Version or help link at bottom */}
          {!collapsed && (
            <div className="mt-4 px-3 pt-4 border-t border-border">
              <p className="text-[10px] text-muted">v1.0.0</p>
            </div>
          )}
        </aside>

        {/* Main content */}
        <main
          className="flex-1 overflow-auto p-6"
          role="main"
        >
          {children}
        </main>
      </div>
    </div>
  );
}

